"""Paper-fill ledger for dry-run sessions.

Simulates fills at the quoted price (buy at ask, sell at the live price — NO
slippage, by design) and tallies realized + open P&L, so a dry-run produces a
real P&L number. Also the foundation for the dashboard P&L and backtesting.
"""

from dataclasses import dataclass
from typing import Dict, List, Optional


@dataclass
class Lot:
    ticker: str
    qty: int
    avg_cost: float  # per-contract premium (2.40 == $240/contract)


@dataclass
class ClosedTrade:
    ticker: str
    qty: int
    entry: float
    exit: float
    pnl: float       # dollars
    reason: str      # trim / close / stop / eod

    @property
    def pct(self) -> float:
        return (self.exit / self.entry - 1) * 100 if self.entry else 0.0


class PaperLedger:
    def __init__(self):
        self.open: Dict[str, Lot] = {}
        self.closed: List[ClosedTrade] = []

    def buy(self, ticker: str, qty: int, price: float) -> None:
        lot = self.open.get(ticker)
        if lot:
            total = lot.avg_cost * lot.qty + price * qty
            lot.qty += qty
            lot.avg_cost = total / lot.qty
        else:
            self.open[ticker] = Lot(ticker, qty, price)

    def sell(self, ticker: str, qty: int, price: float, reason: str = "") -> float:
        lot = self.open.get(ticker)
        if not lot:
            return 0.0
        qty = min(qty, lot.qty)
        pnl = (price - lot.avg_cost) * 100 * qty
        self.closed.append(ClosedTrade(ticker, qty, lot.avg_cost, price, pnl, reason))
        lot.qty -= qty
        if lot.qty <= 0:
            del self.open[ticker]
        return pnl

    def realized(self) -> float:
        return sum(t.pnl for t in self.closed)

    def summary(self, last_prices: Optional[Dict[str, float]] = None) -> str:
        out = []
        r = self.realized()
        wins = [t for t in self.closed if t.pnl > 0]
        losses = [t for t in self.closed if t.pnl < 0]
        out.append(f"Realized P&L: ${r:+,.0f}  over {len(self.closed)} exit(s)")
        if self.closed:
            wr = 100 * len(wins) / len(self.closed)
            out.append(f"  wins {len(wins)} / losses {len(losses)}  ({wr:.0f}% win rate)")
            for t in self.closed:
                out.append(f"    {t.ticker:5} {t.qty}x  {t.entry:.2f} -> {t.exit:.2f}  "
                           f"${t.pnl:+,.0f} ({t.pct:+.0f}%)  [{t.reason}]")
        if self.open:
            out.append("Open (unrealized):")
            for tk, lot in self.open.items():
                lp = (last_prices or {}).get(tk)
                if lp:
                    u = (lp - lot.avg_cost) * 100 * lot.qty
                    out.append(f"    {tk:5} {lot.qty}x @ {lot.avg_cost:.2f} -> "
                               f"{lp:.2f}  ${u:+,.0f}")
                else:
                    out.append(f"    {tk:5} {lot.qty}x @ {lot.avg_cost:.2f}")
        return "\n".join(out)

