"""The safety gate. Every entry passes through here before any order is built.

Given orders auto-fire, this is the most important module in the project:
it's what stands between a misparsed alert and a real fill.
"""

from dataclasses import dataclass
from math import floor
from typing import Optional

from .config import Config
from .models import ParsedAlert


@dataclass
class SizingDecision:
    approved: bool
    quantity: int
    reason: str


class RulesEngine:
    def __init__(self, config: Config):
        self.config = config
        self._trades_today = 0

    def validate_entry(self, alert: ParsedAlert, ask: float) -> SizingDecision:
        c = self.config

        if c.kill_switch:
            return SizingDecision(False, 0, "kill switch is ON")

        if c.paused:
            return SizingDecision(False, 0, "strategy is paused")

        if alert.confidence < 0.6:
            return SizingDecision(False, 0,
                                  f"low parse confidence ({alert.confidence:.2f})")

        if not alert.ticker or alert.ticker.upper() not in {t.upper() for t in c.allowlist}:
            return SizingDecision(False, 0, f"{alert.ticker} not in allowlist")

        if ask is None or ask <= 0:
            return SizingDecision(False, 0, "no valid live quote")

        # Wrong-contract guard: if the live ask is more than max_price_slippage_usd
        # DOLLARS above the alert's quoted price, we probably resolved the wrong
        # expiry/strike. None = guard disabled.
        if (c.max_price_slippage_usd is not None and alert.alert_price
                and ask > alert.alert_price + c.max_price_slippage_usd):
            return SizingDecision(
                False, 0,
                f"live ask ${ask:.2f} > alert ${alert.alert_price:.2f} + "
                f"${c.max_price_slippage_usd:.2f} cap — possible wrong contract")

        if self._trades_today >= c.max_trades_per_day:
            return SizingDecision(False, 0, "daily trade cap reached")

        # Per-weekday budget multiplier (e.g. 50% on Mondays). Missing day = 100%.
        eff_budget = c.trade_budget_usd
        pct = 100
        if getattr(c, "budget_day_pct", None):
            from datetime import datetime
            from zoneinfo import ZoneInfo
            day = datetime.now(ZoneInfo("America/New_York")).strftime("%a").lower()  # mon..sun
            pct = c.budget_day_pct.get(day, 100)
            eff_budget = c.trade_budget_usd * (float(pct) / 100.0)

        cost_per = ask * 100
        qty = floor(eff_budget / cost_per)
        if qty < 1:
            return SizingDecision(
                False, 0,
                f"1 contract costs ${cost_per:.0f} > today's budget ${eff_budget:.0f}")

        qty = min(qty, c.max_contracts_per_trade)
        day_note = f", {pct}% day-budget" if pct != 100 else ""
        return SizingDecision(True, qty,
                              f"{qty} contract(s) @ ~${ask:.2f} (${qty*cost_per:.0f}{day_note})")

    def record_trade(self) -> None:
        self._trades_today += 1

