"""Build Schwab Trader API order payloads for single-leg options.

Schema follows POST /trader/v1/accounts/{accountNumber}/orders.
These are pure dict builders — no network, easy to assert against in tests.
"""

from typing import Dict


def _leg(instruction: str, symbol: str, quantity: int) -> Dict:
    return {
        "instruction": instruction,
        "quantity": quantity,
        "instrument": {"symbol": symbol, "assetType": "OPTION"},
    }


def market_buy(symbol: str, quantity: int) -> Dict:
    return {
        "orderType": "MARKET",
        "session": "NORMAL",
        "duration": "DAY",
        "orderStrategyType": "SINGLE",
        "orderLegCollection": [_leg("BUY_TO_OPEN", symbol, quantity)],
    }


def market_sell(symbol: str, quantity: int) -> Dict:
    return {
        "orderType": "MARKET",
        "session": "NORMAL",
        "duration": "DAY",
        "orderStrategyType": "SINGLE",
        "orderLegCollection": [_leg("SELL_TO_CLOSE", symbol, quantity)],
    }


def limit_buy(symbol: str, quantity: int, limit_price: float) -> Dict:
    """Limit buy — used ONLY for the connection round-trip test. Set the price
    far from the market (e.g. $0.01) so it can never fill, then cancel it."""
    return {
        "orderType": "LIMIT",
        "price": round(limit_price, 2),
        "session": "NORMAL",
        "duration": "DAY",
        "orderStrategyType": "SINGLE",
        "orderLegCollection": [_leg("BUY_TO_OPEN", symbol, quantity)],
    }


def stop_sell(symbol: str, quantity: int, stop_price: float) -> Dict:
    """Resting stop-market sell — our -20% protective exit."""
    return {
        "orderType": "STOP",
        "stopPrice": round(stop_price, 2),
        "session": "NORMAL",
        "duration": "DAY",
        "orderStrategyType": "SINGLE",
        "orderLegCollection": [_leg("SELL_TO_CLOSE", symbol, quantity)],
    }

