"""US equity-market (NYSE) trading calendar — **computed**, so it never needs a
yearly update (no hardcoded table to go stale). Full-day holidays + early-close
("half") days, with NYSE weekend-observance rules:

    holiday on Saturday -> observed the preceding Friday
    holiday on Sunday   -> observed the following Monday

Half days close at 13:00 ET instead of the normal 16:00 ET — the supervisor uses
this to flatten positions and stop the session early.
"""
from datetime import date, timedelta


def _nth_weekday(year: int, month: int, weekday: int, n: int) -> date:
    """n-th `weekday` (Mon=0..Sun=6) of (year, month). n=-1 -> last."""
    if n > 0:
        first = date(year, month, 1)
        return first + timedelta(days=(weekday - first.weekday()) % 7 + 7 * (n - 1))
    last = (date(year, 12, 31) if month == 12
            else date(year, month + 1, 1) - timedelta(days=1))
    return last - timedelta(days=(last.weekday() - weekday) % 7)


def _observed(d: date) -> date:
    if d.weekday() == 5:                 # Saturday -> Friday
        return d - timedelta(days=1)
    if d.weekday() == 6:                 # Sunday -> Monday
        return d + timedelta(days=1)
    return d


def _easter(year: int) -> date:
    """Anonymous Gregorian computus -> Easter Sunday."""
    a = year % 19
    b, c = divmod(year, 100)
    d, e = divmod(b, 4)
    f = (b + 8) // 25
    g = (b - f + 1) // 3
    h = (19 * a + b - d - g + 15) % 30
    i, k = divmod(c, 4)
    ll = (32 + 2 * e + 2 * i - h - k) % 7
    m = (a + 11 * h + 22 * ll) // 451
    month = (h + ll - 7 * m + 114) // 31
    day = ((h + ll - 7 * m + 114) % 31) + 1
    return date(year, month, day)


def holidays(year: int) -> set:
    """NYSE full-close dates for `year`."""
    return {
        _observed(date(year, 1, 1)),            # New Year's Day
        _nth_weekday(year, 1, 0, 3),            # MLK Day (3rd Mon Jan)
        _nth_weekday(year, 2, 0, 3),            # Washington's Birthday (3rd Mon Feb)
        _easter(year) - timedelta(days=2),      # Good Friday
        _nth_weekday(year, 5, 0, -1),           # Memorial Day (last Mon May)
        _observed(date(year, 6, 19)),           # Juneteenth
        _observed(date(year, 7, 4)),            # Independence Day
        _nth_weekday(year, 9, 0, 1),            # Labor Day (1st Mon Sep)
        _nth_weekday(year, 11, 3, 4),           # Thanksgiving (4th Thu Nov)
        _observed(date(year, 12, 25)),          # Christmas
    }


def half_days(year: int) -> set:
    """NYSE early-close (13:00 ET) dates for `year`."""
    out = {_nth_weekday(year, 11, 3, 4) + timedelta(days=1)}     # day after Thanksgiving
    # July 3 — early close when it's a weekday and the 4th is a regular trading weekday.
    if date(year, 7, 4).weekday() < 5 and date(year, 7, 3).weekday() < 5:
        out.add(date(year, 7, 3))
    # Christmas Eve — early close when Dec 24 is a weekday and isn't the observed holiday.
    xeve = date(year, 12, 24)
    if xeve.weekday() < 5 and _observed(date(year, 12, 25)) != xeve:
        out.add(xeve)
    return out


def is_holiday(d: date) -> bool:
    return d in holidays(d.year)


def is_half_day(d: date) -> bool:
    return d in half_days(d.year)


def is_trading_day(d: date) -> bool:
    """A weekday that isn't a full-close holiday (half days still trade, until 13:00)."""
    return d.weekday() < 5 and d not in holidays(d.year)


def close_et(d: date) -> str:
    """Regular close time (ET) for a trading day — '13:00' on half days, else '16:00'."""
    return "13:00" if is_half_day(d) else "16:00"


if __name__ == "__main__":
    # CLI for the supervisor shell script (evaluated in ET, "today"):
    #   python3 -m src.schwab.market_calendar is_trading_day   -> exit 0 if yes, 1 if no
    #   python3 -m src.schwab.market_calendar close_et         -> prints 16:00 / 13:00
    import sys
    from datetime import datetime
    from zoneinfo import ZoneInfo
    _today = datetime.now(ZoneInfo("America/New_York")).date()
    if "is_trading_day" in sys.argv:
        sys.exit(0 if is_trading_day(_today) else 1)
    if "close_et" in sys.argv:
        print(close_et(_today)); sys.exit(0)
    print(f"{_today} trading={is_trading_day(_today)} half={is_half_day(_today)} close_et={close_et(_today)}")
